import { useState } from 'react';
import { useNavigate, Link, useSearchParams } from 'react-router-dom';
import { toast } from 'react-toastify';
import API from '../api/axios';
import { useAuth } from '../context/AuthContext';

export default function Register() {
  const [params] = useSearchParams();
  const [role, setRole] = useState(params.get('role') || 'customer');
  const [form, setForm] = useState({ name: '', email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async () => {
    if (!form.name || !form.email || !form.password) return toast.error('Fill all fields');
    if (form.password.length < 6) return toast.error('Password min 6 characters');
    setLoading(true);
    try {
      const res = await API.post('/auth/register', { ...form, role });
      login(res.data.user, res.data.token);
      toast.success('Account created successfully!');
      navigate(role === 'provider' ? '/dashboard' : '/');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Registration failed');
    }
    setLoading(false);
  };

  return (
    <div style={{
      minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center',
      background: 'radial-gradient(ellipse at center, rgb(172, 109, 231) 0%, #6868f0 70%)',
      padding: '20px'
    }}>
      <div className="glass animate-in" style={{ width: '100%', maxWidth: '460px', padding: '48px 40px' }}>
        <div style={{ textAlign: 'center', marginBottom: '32px' }}>
          <div style={{ fontSize: '48px', marginBottom: '12px' }}>🚀</div>
          <h2 style={{ fontSize: '28px', fontWeight: 800 }}>Create Account</h2>
          <p style={{ color: 'rgba(255,255,255,0.4)', marginTop: '6px' }}>Join thousands of users today</p>
        </div>

        {/* Role Toggle */}
        <div style={{ display: 'flex', background: 'rgba(255,255,255,0.05)', borderRadius: '12px', padding: '4px', marginBottom: '28px' }}>
          {['customer', 'provider'].map(r => (
            <button key={r} onClick={() => setRole(r)} style={{
              flex: 1, padding: '10px', borderRadius: '9px', border: 'none', cursor: 'pointer',
              fontWeight: 600, fontSize: '14px', transition: 'all 0.3s',
              background: role === r ? 'linear-gradient(135deg, #6366f1, #a855f7)' : 'transparent',
              color: role === r ? '#fff' : 'rgba(255,255,255,0.5)'
            }}>
              {r === 'customer' ? '👤 Customer' : '🏪 Service Provider'}
            </button>
          ))}
        </div>

        <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
          <div>
            <label style={{ fontSize: '13px', color: 'rgba(255,255,255,0.6)', marginBottom: '6px', display: 'block' }}>Full Name</label>
            <input className="input-field" placeholder="John Doe"
              onChange={e => setForm({ ...form, name: e.target.value })} />
          </div>
          <div>
            <label style={{ fontSize: '13px', color: 'rgba(255,255,255,0.6)', marginBottom: '6px', display: 'block' }}>Email Address</label>
            <input className="input-field" placeholder="you@example.com" type="email"
              onChange={e => setForm({ ...form, email: e.target.value })} />
          </div>
          <div>
            <label style={{ fontSize: '13px', color: 'rgba(255,255,255,0.6)', marginBottom: '6px', display: 'block' }}>Password</label>
            <input className="input-field" placeholder="Min 6 characters" type="password"
              onChange={e => setForm({ ...form, password: e.target.value })}
              onKeyDown={e => e.key === 'Enter' && handleSubmit()} />
          </div>

          <button className="btn-primary" onClick={handleSubmit} disabled={loading}
            style={{ width: '100%', padding: '14px', fontSize: '15px', marginTop: '8px', opacity: loading ? 0.7 : 1 }}>
            {loading ? '⏳ Creating...' : `Create ${role === 'provider' ? 'Provider' : 'Customer'} Account →`}
          </button>
        </div>

        <p style={{ textAlign: 'center', marginTop: '24px', color: 'rgba(255,255,255,0.4)', fontSize: '14px' }}>
          Already have an account? <Link to="/login" style={{ color: '#a855f7', fontWeight: 600, textDecoration: 'none' }}>Sign in</Link>
        </p>
      </div>
    </div>
  );
}
